def parse_qs(qs):
    from urllib.parse import unquote
    result = {}
    if qs.startswith('?'):
        qs = qs[1:]
    if not qs:
        return result
    for part in qs.split('&'):
        if '=' in part:
            k, v = part.split('=', 1)
        else:
            k, v = part, ''
        k = unquote(k)
        v = unquote(v)
        if k in result:
            result[k].append(v)
        else:
            result[k] = [v]
    return result

