class Heap:
    def __init__(self, compare):
        self.compare = compare
        self.data = []  # list of (item, insertion_counter) pairs
        self._seq = 0

    def _cmp(self, i, j):
        a, ai = self.data[i]
        b, bj = self.data[j]
        c = self.compare(a, b)
        if c != 0:
            return c
        return ai - bj

    def push(self, item):
        self._seq += 1
        self.data.append((item, self._seq))
        self._sift_up(len(self.data) - 1)

    def pop(self):
        if not self.data:
            raise IndexError('pop from empty heap')
        top = self.data[0][0]
        last = self.data.pop()
        if self.data:
            self.data[0] = last
            self._sift_down(0)
        return top

    def peek(self):
        return self.data[0][0]

    def _sift_up(self, i):
        while i > 0:
            parent = (i - 1) // 2
            if self._cmp(i, parent) < 0:
                self.data[i], self.data[parent] = self.data[parent], self.data[i]
                i = parent
            else:
                break

    def _sift_down(self, i):
        n = len(self.data)
        while True:
            left = 2 * i + 1
            right = 2 * i + 2
            smallest = i
            if left < n and self._cmp(left, smallest) < 0:
