class RingBuffer:
    """Fixed-capacity single-reader single-writer ring buffer.
    Writes never block; when full, the oldest element is dropped (overwrite).
    """

    def __init__(self, capacity):
        if capacity <= 0:
            raise ValueError('capacity must be positive')
        self.capacity = capacity
        self.buf = [None] * capacity
        self.r = 0
        self.w = 0
        self.size = 0

    def write(self, x):
        self.buf[self.w] = x
        self.w = (self.w + 1) % self.capacity
        if self.size < self.capacity:
            self.size += 1
        else:
            # Advance read pointer on overwrite
            self.r = (self.r + 1) % self.capacity

    def read(self):
        if self.size == 0:
            raise IndexError('read from empty buffer')
        x = self.buf[self.r]
        self.r = (self.r + 1) % self.capacity
        self.size -= 1
        return x

    def peek(self):
        if self.size == 0:
            raise IndexError('peek on empty buffer')
        return self.buf[self.r]

    def __len__(self):
        return self.size

import unicodedata

def truncate_graphemes(s, n):
    if n <= 0:
        return ''
    clusters = []
    i = 0
    while i < len(s) and len(clusters) < n:
        char = s[i]
        # Rule 1: Base character starts a new cluster
        if unicodedata.category(char).startswith('M') or char == '\u200d' or unicodedata.category(char) == 'Lo' or unicodedata.category(char) == 'Lu':
            # Rule 2: Combining marks, ZWJ, or base characters extend current cluster
            # Rule 3: ZWJ joins next character into same cluster
            # Rule 4: Regional indicators pair with next if it's the same
            # Rule 5: Variation selectors extend current cluster
            # Check if current character is a variation selector
            if unicodedata.category(char) == 'Cs' and char.startswith('\uFE0'):
                # Extend current cluster
                clusters[-1] += char
            else:
                # Start new cluster
                clusters.append(char)
            i += 1
        else:
            # Rule 4: Regional indicators pair with next if it's the same
            if unicodedata.category(char) == 'Lo' and i + 1 < len(s) and unicodedata.category(s[i + 1]) == 'Lo':
                clusters.append(char + s[i + 1])
                i += 2
            else:
                clusters.append(char)
                i += 1
    return ''.join(clusters[:n])

